import "server-only";

// VENDORED firecrawl skills. firecrawl-cli does NOT ship SKILL.md in its npm
// package (its skills install over the network via `firecrawl init`), so we
// vendor our own copies here — offline, deterministic, no foreign fetch at
// build. Each carries a Knack note (load FIRECRAWL_API_KEY via secret_get).
// Source: github.com/firecrawl/cli (skills/<name>/SKILL.md). Regenerate with
// scripts/vendor-firecrawl-skills.* when firecrawl updates.

export type VendoredSkill = { name: string; content: string };

export const VENDORED_FIRECRAWL_SKILLS: VendoredSkill[] = [
  {
    "name": "firecrawl-agent",
    "content": "---\nname: firecrawl-agent\ndescription: |\n  AI-powered autonomous data extraction that navigates complex sites and returns structured JSON. Use this skill when the user wants structured data from websites, needs to extract pricing tiers, product listings, directory entries, or any data as JSON with a schema. Triggers on \"extract structured data\", \"get all the products\", \"pull pricing info\", \"extract as JSON\", or when the user provides a JSON schema for website data. More powerful than simple scraping for multi-page structured extraction.\nallowed-tools:\n  - Bash(firecrawl *)\n  - Bash(npx firecrawl *)\n---\n\n# firecrawl agent\n\nAI-powered autonomous extraction. The agent navigates sites and extracts structured data (takes 2-5 minutes).\n\n## When to use\n\n- You need structured data from complex multi-page sites\n- Manual scraping would require navigating many pages\n- You want the AI to figure out where the data lives\n\n## Quick start\n\n```bash\n# Extract structured data\nfirecrawl agent \"extract all pricing tiers\" --wait -o .firecrawl/pricing.json\n\n# With a JSON schema for structured output\nfirecrawl agent \"extract products\" --schema '{\"type\":\"object\",\"properties\":{\"name\":{\"type\":\"string\"},\"price\":{\"type\":\"number\"}}}' --wait -o .firecrawl/products.json\n\n# Focus on specific pages\nfirecrawl agent \"get feature list\" --urls \"<url>\" --wait -o .firecrawl/features.json\n```\n\n## Options\n\n| Option                 | Description                               |\n| ---------------------- | ----------------------------------------- |\n| `--urls <urls>`        | Starting URLs for the agent               |\n| `--model <model>`      | Model to use: spark-1-mini or spark-1-pro |\n| `--schema <json>`      | JSON schema for structured output         |\n| `--schema-file <path>` | Path to JSON schema file                  |\n| `--max-credits <n>`    | Credit limit for this agent run           |\n| `--wait`               | Wait for agent to complete                |\n| `--pretty`             | Pretty print JSON output                  |\n| `-o, --output <path>`  | Output file path                          |\n\n## Tips\n\n- Always use `--wait` to get results inline. Without it, returns a job ID.\n- Use `--schema` for predictable, structured output — otherwise the agent returns freeform data.\n- Agent runs consume more credits than simple scrapes. Use `--max-credits` to cap spending.\n- For simple single-page extraction, prefer `scrape` — it's faster and cheaper.\n\n## See also\n\n- [firecrawl-scrape](../firecrawl-scrape/SKILL.md) — simpler single-page extraction\n- [firecrawl-interact](../firecrawl-interact/SKILL.md) — scrape + interact for manual page interaction (more control)\n- [firecrawl-crawl](../firecrawl-crawl/SKILL.md) — bulk extraction without AI\n\n## Running in Knack\nThis sandbox has no `FIRECRAWL_API_KEY` by default. Before running any `firecrawl` / `firecrawl-cli` command, load the user's key from the secrets vault with the `secret_get` tool (name: `FIRECRAWL_API_KEY`) and export it in the same shell, e.g. `export FIRECRAWL_API_KEY=<value> && firecrawl ...`. If the secret is missing, ask the user to add it in Settings → Secrets.\n"
  },
  {
    "name": "firecrawl-cli",
    "content": "---\nname: firecrawl\ndescription: |\n  Search, scrape, and interact with the web via the Firecrawl CLI. Use this skill whenever the user wants to search the web, find articles, research a topic, look something up online, scrape a webpage, grab content from a URL, get data from a website, crawl documentation, download a site, or interact with pages that need clicks or logins. Also use when they say \"fetch this page\", \"pull the content from\", \"get the page at https://\", or reference external websites. This provides real-time web search with full page content and interact capabilities — beyond what Claude can do natively with built-in tools. Do NOT trigger for local file operations, git commands, deployments, or code editing tasks.\nallowed-tools:\n  - Bash(firecrawl *)\n  - Bash(npx firecrawl *)\n---\n\n# Firecrawl CLI\n\nSearch, scrape, and interact with the web. Returns clean markdown optimized for LLM context windows.\n\nRun `firecrawl --help` or `firecrawl <command> --help` for full option details.\n\nIf the task is to integrate Firecrawl into an application, add `FIRECRAWL_API_KEY` to a project, or choose endpoint usage in product code, use the `firecrawl-build` skills. If the task is an outcome workflow such as deep research, SEO audit, QA, lead generation, knowledge-base creation, dashboard reporting, shopping research, or website design-system extraction, use the `firecrawl-workflows` skills. They are already installed alongside this CLI skill when you run `firecrawl init`.\n\n## Prerequisites\n\nMust be installed and authenticated. Check with `firecrawl --status`.\n\n```\n  🔥 firecrawl cli v1.8.0\n\n  ● Authenticated via FIRECRAWL_API_KEY\n  Concurrency: 0/100 jobs (parallel scrape limit)\n  Credits: 500,000 remaining\n```\n\n- **Concurrency**: Max parallel jobs. Run parallel operations up to this limit.\n- **Credits**: Remaining API credits. Each operation consumes credits.\n\nIf not ready, see [rules/install.md](rules/install.md). For output handling guidelines, see [rules/security.md](rules/security.md).\n\nBefore doing real work, verify the setup with one small request:\n\n```bash\nmkdir -p .firecrawl\nfirecrawl scrape \"https://firecrawl.dev\" -o .firecrawl/install-check.md\n```\n\n```bash\nfirecrawl search \"query\" --scrape --limit 3\n```\n\n## Workflow\n\nFollow this escalation pattern:\n\n1. **Search** - No specific URL yet. Find pages, answer questions, discover sources.\n2. **Scrape** - Have a URL. Extract its content directly.\n3. **Map + Scrape** - Large site or need a specific subpage. Use `map --search` to find the right URL, then scrape it.\n4. **Crawl** - Need bulk content from an entire site section (e.g., all /docs/).\n5. **Monitor** - Need recurring checks or ongoing alerts. Prefer setting a monitor with `--page` plus `--goal` instead of doing repeated one-off scrapes.\n6. **Interact** - Scrape first, then interact with the page (pagination, modals, form submissions, multi-step navigation).\n\n| Need                        | Command               | When                                                      |\n| --------------------------- | --------------------- | --------------------------------------------------------- |\n| Find pages on a topic       | `search`              | No specific URL yet                                       |\n| Get a page's content        | `scrape`              | Have a URL, page is static or JS-rendered                 |\n| Find URLs within a site     | `map`                 | Need to locate a specific subpage                         |\n| Bulk extract a site section | `crawl`               | Need many pages (e.g., all /docs/)                        |\n| AI-powered data extraction  | `agent`               | Need structured data from complex sites                   |\n| Interact with a page        | `scrape` + `interact` | Content requires clicks, form fills, pagination, or login |\n| Download a site to files    | `download`            | Save an entire site as local files                        |\n| Parse a local file          | `parse`               | File on disk (PDF, DOCX, XLSX, etc.) — not a URL          |\n| Watch pages for changes     | `monitor`             | Schedule recurring scrapes/crawls, diff against snapshots |\n\nFor detailed command reference, run `firecrawl <command> --help`.\n\n**Scrape vs interact:**\n\n- Use `scrape` first. It handles static pages and JS-rendered SPAs.\n- Use `scrape` + `interact` when you need to interact with a page, such as clicking buttons, filling out forms, navigating through a complex site, infinite scroll, or when scrape fails to grab all the content you need.\n- Never use interact for web searches - use `search` instead.\n\n**Monitor:** Schedule recurring scrapes or crawls and diff each result against the last retained snapshot. Bias toward `monitor` when the user's goal is ongoing change detection, alerting, or repeated checks over time. For a single page, default to setting a monitor with `--page <url>` and `--goal \"...\"`. Use for product pages, docs, blogs, changelogs, competitor sites — any page where changes matter. Each monitor should include a short `goal` describing what changes matter, and each check labels pages as `same`, `new`, `changed`, `removed`, or `error`, with webhook and email notification options.\n\nWhen writing `--goal`, convert the user's monitoring intent into a concise 2-3 sentence monitor goal, similar to the web app setup flow:\n\n- Start with `Alert when ...` and state what should trigger an alert using the user's stated intent.\n- Restate scope the user mentioned, such as top N, price, role type, company, region, topic, status, or a specific entity.\n- Include an `Ignore ...` sentence only for intent-specific exclusions that are obvious from the request, such as points/comments for rankings, unrelated marketing copy for pricing, or general company-page updates for jobs.\n- Do not repeat generic noise exclusions in every goal; the judge already handles whitespace, casing, punctuation, encoding, formatting-only changes, request/session IDs, cache busters, tracking params, generic metadata noise, and unrelated page chrome.\n- Do not invent page-specific sections, entities, thresholds, exclusions, or business rules unless the user mentioned them.\n- If the user is vague, keep the goal broad rather than guessing exclusions.\n- If the user asks for \"any change\", preserve that and do not add exclusions.\n- If the user mentions noise they do not care about, include that explicitly.\n\nGood goal examples:\n\n- User intent: `top 10 hackernews stories`\n  Goal: `Alert when stories enter, leave, or change rank within the Hacker News top 10. Ignore points, comments, and timestamps. Do not alert on changes outside the top 10.`\n- User intent: `pricing changes`\n  Goal: `Alert when pricing information changes, including prices, plan names, billing periods, tiers, limits, or included features. Ignore unrelated marketing copy, testimonials, and regional currency display changes unless the underlying offer changes.`\n- User intent: `new engineering roles`\n  Goal: `Alert when a new engineering role is posted. Ignore general company-page updates unless they add, remove, or change an engineering role.`\n- User intent: `track this page`\n  Goal: `Alert when substantive visible content on this page changes.`\n- User intent: `any change`\n  Goal: `Alert when any visible page content changes, including copy, numbers, timestamps, counters, links, and layout text.`\n\nSubcommands: `create | list | get | update | delete | run | checks | check`.\n\n```bash\n# create from flags\nfirecrawl monitor create --name \"Blog\" --schedule \"every 5 minutes\" \\\n  --goal \"Alert when a new blog post is published.\" \\\n  --page https://example.com/blog --email alerts@example.com\n\n# multiple pages\nfirecrawl monitor create --name \"Product pages\" --schedule \"every 5 minutes\" \\\n  --goal \"Alert when pricing, docs, or changelog content changes.\" \\\n  --scrape-urls https://example.com/pricing,https://example.com/docs,https://example.com/changelog\n\n# webhook notifications\nfirecrawl monitor create --name \"Docs webhook\" --schedule \"every 5 minutes\" \\\n  --goal \"Alert when docs content changes.\" \\\n  --page https://example.com/docs \\\n  --webhook-url https://example.com/webhook \\\n  --webhook-events monitor.page,monitor.check.completed\n\n# or from JSON (positional file, or piped stdin)\nfirecrawl monitor create monitor.json\ncat monitor.json | firecrawl monitor create\n\nfirecrawl monitor list --limit 20\nfirecrawl monitor run <monitorId>             # trigger a check now\nfirecrawl monitor checks <monitorId>          # list checks\nfirecrawl monitor check <monitorId> <checkId> --page-status changed\nfirecrawl monitor update <monitorId> --state paused\nfirecrawl monitor delete <monitorId>\n```\n\nSchedules accept cron (`--cron \"*/5 * * * *\"`) or natural language (`--schedule \"every 5 minutes\"`). Minimum interval is 5 minutes. Targets are `--page <url>` for one page, `--scrape-urls a,b,c` for multiple scrape URLs, or `--crawl-url <url>` for a whole-site crawl each check. Use `--goal` for flag-based monitor creation, or include `\"goal\": \"...\"` in JSON payloads. Note: `--state` (not `--status`) sets active/paused; `--page-status` (not `--status`) filters page results on `check` — avoids collision with the global `--status` flag. Monitoring is not available for zero-data-retention teams.\n\n**JSON-mode change tracking:** By default monitors diff each page's markdown and you get a unified text diff back. When you care about **specific structured fields** (price, headline, in-stock flag, items in a list) instead of the whole page, add a `changeTracking` format with `modes: [\"json\"]` and a JSON schema to the target's `scrapeOptions.formats`. The flag-based form doesn't cover this — pass a JSON body via file or stdin:\n\n```bash\ncat > pricing-monitor.json <<'EOF'\n{\n  \"name\": \"Pricing watch\",\n  \"goal\": \"Alert when plan prices or headline features change\",\n  \"schedule\": { \"text\": \"hourly\", \"timezone\": \"UTC\" },\n  \"targets\": [{\n    \"type\": \"scrape\",\n    \"urls\": [\"https://example.com/pricing\"],\n    \"scrapeOptions\": {\n      \"formats\": [{\n        \"type\": \"changeTracking\",\n        \"modes\": [\"json\"],\n        \"prompt\": \"Extract pricing tiers and headline features for each plan.\",\n        \"schema\": {\n          \"type\": \"object\",\n          \"properties\": {\n            \"plans\": {\n              \"type\": \"array\",\n              \"items\": {\n                \"type\": \"object\",\n                \"properties\": {\n                  \"name\":     { \"type\": \"string\" },\n                  \"price\":    { \"type\": \"string\" },\n                  \"features\": { \"type\": \"array\", \"items\": { \"type\": \"string\" } }\n                }\n              }\n            }\n          }\n        }\n      }]\n    }\n  }]\n}\nEOF\nfirecrawl monitor create pricing-monitor.json\n```\n\nThe `check` response then carries a per-field diff (paths like `plans[0].price`) and the full extraction at this run, instead of (or in addition to) a markdown diff. Each changed page in `pages[]` looks like:\n\n```json\n{\n  \"url\": \"https://example.com/pricing\",\n  \"status\": \"changed\",\n  \"diff\": {\n    \"json\": {\n      \"plans[0].price\": { \"previous\": \"$19/mo\", \"current\": \"$24/mo\" },\n      \"plans[1].features[2]\": {\n        \"previous\": \"10 GB storage\",\n        \"current\": \"25 GB storage\"\n      }\n    }\n  },\n  \"snapshot\": {\n    \"json\": {\n      \"plans\": [\n        /* current full extraction */\n      ]\n    }\n  }\n}\n```\n\nUse `modes: [\"json\", \"git-diff\"]` for **mixed mode**: you get both `diff.json` (per-field) and `diff.text` (markdown sidecar), and the page is marked `changed` whenever either surface changed. For markdown-only monitors, `diff.text` holds the unified diff and `diff.json` is a `parse-diff` AST (`{ files: [...] }`); there is no `snapshot`.\n\n**Avoid redundant fetches:**\n\n- `search --scrape` already fetches full page content. Don't re-scrape those URLs.\n- Check `.firecrawl/` for existing data before fetching again.\n\n## When to Load References\n\n- **Searching the web or finding sources first** -> [firecrawl-search](../firecrawl-search/SKILL.md)\n- **Scraping a known URL** -> [firecrawl-scrape](../firecrawl-scrape/SKILL.md)\n- **Finding URLs on a known site** -> [firecrawl-map](../firecrawl-map/SKILL.md)\n- **Bulk extraction from a docs section or site** -> [firecrawl-crawl](../firecrawl-crawl/SKILL.md)\n- **AI-powered structured extraction from complex sites** -> [firecrawl-agent](../firecrawl-agent/SKILL.md)\n- **Clicks, forms, login, pagination, or post-scrape browser actions** -> [firecrawl-interact](../firecrawl-interact/SKILL.md)\n- **Downloading a site to local files** -> [firecrawl-download](../firecrawl-download/SKILL.md)\n- **Parsing a local file (PDF, DOCX, XLSX, HTML, etc.)** -> [firecrawl-parse](../firecrawl-parse/SKILL.md)\n- **Detecting content changes on a website and getting notified by webhook or email (pricing, jobs, posts, docs, status pages, anything ongoing)** -> [firecrawl-monitor](../firecrawl-monitor/SKILL.md)\n- **Install, auth, or setup problems** -> [rules/install.md](rules/install.md)\n- **Output handling and safe file-reading patterns** -> [rules/security.md](rules/security.md)\n- **Integrating Firecrawl into an app, adding `FIRECRAWL_API_KEY` to `.env`, or choosing endpoint usage in product code** -> use the `firecrawl-build` skills (already installed alongside this CLI skill)\n- **Producing Firecrawl-powered deliverables such as research briefs, SEO audits, QA reports, lead lists, knowledge bases, or design-system extraction** -> use the `firecrawl-workflows` skills (already installed alongside this CLI skill). These skills infer from context first and ask only short blocking questions when needed.\n\n## Output & Organization\n\nUnless the user specifies to return in context, write results to `.firecrawl/` with `-o`. Add `.firecrawl/` to `.gitignore`. Always quote URLs - shell interprets `?` and `&` as special characters.\n\n```bash\nfirecrawl search \"react hooks\" -o .firecrawl/search-react-hooks.json --json\nfirecrawl scrape \"<url>\" -o .firecrawl/page.md\n```\n\nNaming conventions:\n\n```\n.firecrawl/search-{query}.json\n.firecrawl/search-{query}-scraped.json\n.firecrawl/{site}-{path}.md\n```\n\nNever read entire output files at once. Use `grep`, `head`, or incremental reads:\n\n```bash\nwc -l .firecrawl/file.md && head -50 .firecrawl/file.md\ngrep -n \"keyword\" .firecrawl/file.md\n```\n\nSingle format outputs raw content. Multiple formats (e.g., `--format markdown,links`) output JSON.\n\n## Working with Results\n\nThese patterns are useful when working with file-based output (`-o` flag) for complex tasks:\n\n```bash\n# Extract URLs from search\njq -r '.data.web[].url' .firecrawl/search.json\n\n# Get titles and URLs\njq -r '.data.web[] | \"\\(.title): \\(.url)\"' .firecrawl/search.json\n```\n\n## After search: send feedback (refunds 1 credit)\n\nSearch costs 2 credits per call. **After you finish using a search result**, send structured feedback in the background. The first feedback per search id refunds 1 credit and feeds search-quality improvements.\n\n```bash\nSEARCH_ID=$(jq -r '.id' .firecrawl/search-react-hooks.json)\n\nfirecrawl search-feedback \"$SEARCH_ID\" \\\n  --rating good \\\n  --valuable-sources '[{\"url\":\"https://react.dev/reference/react/hooks\",\"reason\":\"Authoritative\"}]' \\\n  --missing-content '[{\"topic\":\"useDeferredValue example\"},{\"topic\":\"Server Components hooks\"}]' \\\n  --query-suggestions \"Boost react.dev for react-hooks queries\" \\\n  --silent &\n```\n\nThe most useful field is `--missing-content`: an _array_ of specific pieces of content you expected to find but didn't. Use one entry per missing topic. Bad/partial feedback with detailed `--missing-content` is just as valuable as good feedback.\n\n**Opt out:** `export FIRECRAWL_NO_SEARCH_FEEDBACK=1` makes the CLI skip every feedback call silently. Respect that flag — do not try to work around it. See [firecrawl-search](../firecrawl-search/SKILL.md) for the full pattern.\n\n## Endpoint job feedback\n\nFor non-search endpoint jobs, use `firecrawl feedback <endpoint> <jobId>` to send concise job-level feedback through `/v2/feedback`. Supported endpoints are `search`, `scrape`, `parse`, and `map`.\n\n```bash\nfirecrawl feedback scrape \"$SCRAPE_ID\" \\\n  --rating partial \\\n  --issues missing_markdown \\\n  --tags docs \\\n  --note \"The pricing table was missing from the markdown output.\" \\\n  --url \"https://example.com/pricing\" \\\n  --page-numbers 1 \\\n  --silent &\n```\n\nKeep generic feedback small: issue codes, tags, short notes, URLs, page numbers, and small metadata objects. Do not send raw scrape/parse outputs or full page contents as feedback.\n\n**Opt out:** `export FIRECRAWL_NO_ENDPOINT_FEEDBACK=1` makes the CLI skip every endpoint feedback call silently. Respect that flag — do not try to work around it.\n\n## Parallelization\n\nRun independent operations in parallel. Check `firecrawl --status` for concurrency limit:\n\n```bash\nfirecrawl scrape \"<url-1>\" -o .firecrawl/1.md &\nfirecrawl scrape \"<url-2>\" -o .firecrawl/2.md &\nfirecrawl scrape \"<url-3>\" -o .firecrawl/3.md &\nwait\n```\n\nFor interact, scrape multiple pages and interact with each independently using their scrape IDs.\n\n## Credit Usage\n\n```bash\nfirecrawl credit-usage\nfirecrawl credit-usage --json --pretty -o .firecrawl/credits.json\n```\n\n## Running in Knack\nThis sandbox has no `FIRECRAWL_API_KEY` by default. Before running any `firecrawl` / `firecrawl-cli` command, load the user's key from the secrets vault with the `secret_get` tool (name: `FIRECRAWL_API_KEY`) and export it in the same shell, e.g. `export FIRECRAWL_API_KEY=<value> && firecrawl ...`. If the secret is missing, ask the user to add it in Settings → Secrets.\n"
  },
  {
    "name": "firecrawl-crawl",
    "content": "---\nname: firecrawl-crawl\ndescription: |\n  Bulk extract content from an entire website or site section. Use this skill when the user wants to crawl a site, extract all pages from a docs section, bulk-scrape multiple pages following links, or says \"crawl\", \"get all the pages\", \"extract everything under /docs\", \"bulk extract\", or needs content from many pages on the same site. Handles depth limits, path filtering, and concurrent extraction.\nallowed-tools:\n  - Bash(firecrawl *)\n  - Bash(npx firecrawl *)\n---\n\n# firecrawl crawl\n\nBulk extract content from a website. Crawls pages following links up to a depth/limit.\n\n## When to use\n\n- You need content from many pages on a site (e.g., all `/docs/`)\n- You want to extract an entire site section\n- Step 4 in the [workflow escalation pattern](firecrawl-cli): search → scrape → map → **crawl** → interact\n\n## Quick start\n\n```bash\n# Crawl a docs section\nfirecrawl crawl \"<url>\" --include-paths /docs --limit 50 --wait -o .firecrawl/crawl.json\n\n# Full crawl with depth limit\nfirecrawl crawl \"<url>\" --max-depth 3 --wait --progress -o .firecrawl/crawl.json\n\n# Check status of a running crawl\nfirecrawl crawl <job-id>\n```\n\n## Options\n\n| Option                    | Description                                 |\n| ------------------------- | ------------------------------------------- |\n| `--wait`                  | Wait for crawl to complete before returning |\n| `--progress`              | Show progress while waiting                 |\n| `--limit <n>`             | Max pages to crawl                          |\n| `--max-depth <n>`         | Max link depth to follow                    |\n| `--include-paths <paths>` | Only crawl URLs matching these paths        |\n| `--exclude-paths <paths>` | Skip URLs matching these paths              |\n| `--delay <ms>`            | Delay between requests                      |\n| `--max-concurrency <n>`   | Max parallel crawl workers                  |\n| `--pretty`                | Pretty print JSON output                    |\n| `-o, --output <path>`     | Output file path                            |\n\n## Tips\n\n- Always use `--wait` when you need the results immediately. Without it, crawl returns a job ID for async polling.\n- Use `--include-paths` to scope the crawl — don't crawl an entire site when you only need one section.\n- Crawl consumes credits per page. Check `firecrawl credit-usage` before large crawls.\n\n## See also\n\n- [firecrawl-scrape](../firecrawl-scrape/SKILL.md) — scrape individual pages\n- [firecrawl-map](../firecrawl-map/SKILL.md) — discover URLs before deciding to crawl\n- [firecrawl-download](../firecrawl-download/SKILL.md) — download site to local files (uses map + scrape)\n\n## Running in Knack\nThis sandbox has no `FIRECRAWL_API_KEY` by default. Before running any `firecrawl` / `firecrawl-cli` command, load the user's key from the secrets vault with the `secret_get` tool (name: `FIRECRAWL_API_KEY`) and export it in the same shell, e.g. `export FIRECRAWL_API_KEY=<value> && firecrawl ...`. If the secret is missing, ask the user to add it in Settings → Secrets.\n"
  },
  {
    "name": "firecrawl-download",
    "content": "---\nname: firecrawl-download\ndescription: |\n  Download an entire website as local files — markdown, screenshots, or multiple formats per page. Use this skill when the user wants to save a site locally, download documentation for offline use, bulk-save pages as files, or says \"download the site\", \"save as local files\", \"offline copy\", \"download all the docs\", or \"save for reference\". Combines site mapping and scraping into organized local directories.\nallowed-tools:\n  - Bash(firecrawl *)\n  - Bash(npx firecrawl *)\n---\n\n# firecrawl download\n\n> **Experimental.** Convenience command that combines `map` + `scrape` to save an entire site as local files.\n\nMaps the site first to discover pages, then scrapes each one into nested directories under `.firecrawl/`. All scrape options work with download. Always pass `-y` to skip the confirmation prompt.\n\n## When to use\n\n- You want to save an entire site (or section) to local files\n- You need offline access to documentation or content\n- Bulk content extraction with organized file structure\n\n## Quick start\n\n```bash\n# Interactive wizard (picks format, screenshots, paths for you)\nfirecrawl download https://docs.example.com\n\n# With screenshots\nfirecrawl download https://docs.example.com --screenshot --limit 20 -y\n\n# Multiple formats (each saved as its own file per page)\nfirecrawl download https://docs.example.com --format markdown,links --screenshot --limit 20 -y\n# Creates per page: index.md + links.txt + screenshot.png\n\n# Filter to specific sections\nfirecrawl download https://docs.example.com --include-paths \"/features,/sdks\"\n\n# Skip translations\nfirecrawl download https://docs.example.com --exclude-paths \"/zh,/ja,/fr,/es,/pt-BR\"\n\n# Full combo\nfirecrawl download https://docs.example.com \\\n  --include-paths \"/features,/sdks\" \\\n  --exclude-paths \"/zh,/ja\" \\\n  --only-main-content \\\n  --screenshot \\\n  -y\n```\n\n## Download options\n\n| Option                    | Description                                              |\n| ------------------------- | -------------------------------------------------------- |\n| `--limit <n>`             | Max pages to download                                    |\n| `--search <query>`        | Filter URLs by search query                              |\n| `--include-paths <paths>` | Only download matching paths                             |\n| `--exclude-paths <paths>` | Skip matching paths                                      |\n| `--allow-subdomains`      | Include subdomain pages                                  |\n| `-y`                      | Skip confirmation prompt (always use in automated flows) |\n\n## Scrape options (all work with download)\n\n`-f <formats>`, `-H`, `-S`, `--screenshot`, `--full-page-screenshot`, `--only-main-content`, `--include-tags`, `--exclude-tags`, `--wait-for`, `--max-age`, `--country`, `--languages`\n\n## See also\n\n- [firecrawl-map](../firecrawl-map/SKILL.md) — just discover URLs without downloading\n- [firecrawl-scrape](../firecrawl-scrape/SKILL.md) — scrape individual pages\n- [firecrawl-crawl](../firecrawl-crawl/SKILL.md) — bulk extract as JSON (not local files)\n\n## Running in Knack\nThis sandbox has no `FIRECRAWL_API_KEY` by default. Before running any `firecrawl` / `firecrawl-cli` command, load the user's key from the secrets vault with the `secret_get` tool (name: `FIRECRAWL_API_KEY`) and export it in the same shell, e.g. `export FIRECRAWL_API_KEY=<value> && firecrawl ...`. If the secret is missing, ask the user to add it in Settings → Secrets.\n"
  },
  {
    "name": "firecrawl-interact",
    "content": "---\nname: firecrawl-interact\ndescription: |\n  Control and interact with a live browser session on any scraped page — click buttons, fill forms, navigate flows, and extract data using natural language prompts or code. Use when the user needs to interact with a webpage beyond simple scraping: logging into a site, submitting forms, clicking through pagination, handling infinite scroll, navigating multi-step checkout or wizard flows, or when a regular scrape failed because content is behind JavaScript interaction. Also useful for authenticated scraping via profiles. Triggers on \"interact\", \"click\", \"fill out the form\", \"log in to\", \"sign in\", \"submit\", \"paginated\", \"next page\", \"infinite scroll\", \"interact with the page\", \"navigate to\", \"open a session\", or \"scrape failed\".\nallowed-tools:\n  - Bash(firecrawl *)\n  - Bash(npx firecrawl *)\n---\n\n# firecrawl interact\n\nInteract with scraped pages in a live browser session. Scrape a page first, then use natural language prompts or code to click, fill forms, navigate, and extract data.\n\n## When to use\n\n- Content requires interaction: clicks, form fills, pagination, login\n- `scrape` failed because content is behind JavaScript interaction\n- You need to navigate a multi-step flow\n- Last resort in the [workflow escalation pattern](firecrawl-cli): search → scrape → map → crawl → **interact**\n- **Never use interact for web searches** — use `search` instead\n\n## Quick start\n\n```bash\n# 1. Scrape a page (scrape ID is saved automatically)\nfirecrawl scrape \"<url>\"\n\n# 2. Interact with the page using natural language\nfirecrawl interact --prompt \"Click the login button\"\nfirecrawl interact --prompt \"Fill in the email field with test@example.com\"\nfirecrawl interact --prompt \"Extract the pricing table\"\n\n# 3. Or use code for precise control\nfirecrawl interact --code \"agent-browser click @e5\" --language bash\nfirecrawl interact --code \"agent-browser snapshot -i\" --language bash\n\n# 4. Stop the session when done\nfirecrawl interact stop\n```\n\n## Options\n\n| Option                | Description                                       |\n| --------------------- | ------------------------------------------------- |\n| `--prompt <text>`     | Natural language instruction (use this OR --code) |\n| `--code <code>`       | Code to execute in the browser session            |\n| `--language <lang>`   | Language for code: bash, python, node             |\n| `--timeout <seconds>` | Execution timeout (default: 30, max: 300)         |\n| `--scrape-id <id>`    | Target a specific scrape (default: last scrape)   |\n| `-o, --output <path>` | Output file path                                  |\n\n## Profiles\n\nUse `--profile` on the scrape to persist browser state (cookies, localStorage) across scrapes:\n\n```bash\n# Session 1: Login and save state\nfirecrawl scrape \"https://app.example.com/login\" --profile my-app\nfirecrawl interact --prompt \"Fill in email with user@example.com and click login\"\n\n# Session 2: Come back authenticated\nfirecrawl scrape \"https://app.example.com/dashboard\" --profile my-app\nfirecrawl interact --prompt \"Extract the dashboard data\"\n```\n\nRead-only reconnect (no writes to profile state):\n\n```bash\nfirecrawl scrape \"https://app.example.com\" --profile my-app --no-save-changes\n```\n\n## Tips\n\n- Always scrape first — `interact` requires a scrape ID from a previous `firecrawl scrape` call\n- The scrape ID is saved automatically, so you don't need `--scrape-id` for subsequent interact calls\n- Use `firecrawl interact stop` to free resources when done\n- For parallel work, scrape multiple pages and interact with each using `--scrape-id`\n\n## See also\n\n- [firecrawl-scrape](../firecrawl-scrape/SKILL.md) — try scrape first, escalate to interact only when needed\n- [firecrawl-search](../firecrawl-search/SKILL.md) — for web searches (never use interact for searching)\n- [firecrawl-agent](../firecrawl-agent/SKILL.md) — AI-powered extraction (less manual control)\n\n## Running in Knack\nThis sandbox has no `FIRECRAWL_API_KEY` by default. Before running any `firecrawl` / `firecrawl-cli` command, load the user's key from the secrets vault with the `secret_get` tool (name: `FIRECRAWL_API_KEY`) and export it in the same shell, e.g. `export FIRECRAWL_API_KEY=<value> && firecrawl ...`. If the secret is missing, ask the user to add it in Settings → Secrets.\n"
  },
  {
    "name": "firecrawl-map",
    "content": "---\nname: firecrawl-map\ndescription: |\n  Discover and list all URLs on a website, with optional search filtering. Use this skill when the user wants to find a specific page on a large site, list all URLs, see the site structure, find where something is on a domain, or says \"map the site\", \"find the URL for\", \"what pages are on\", or \"list all pages\". Essential when the user knows which site but not which exact page.\nallowed-tools:\n  - Bash(firecrawl *)\n  - Bash(npx firecrawl *)\n---\n\n# firecrawl map\n\nDiscover URLs on a site. Use `--search` to find a specific page within a large site.\n\n## When to use\n\n- You need to find a specific subpage on a large site\n- You want a list of all URLs on a site before scraping or crawling\n- Step 3 in the [workflow escalation pattern](firecrawl-cli): search → scrape → **map** → crawl → interact\n\n## Quick start\n\n```bash\n# Find a specific page on a large site\nfirecrawl map \"<url>\" --search \"authentication\" -o .firecrawl/filtered.txt\n\n# Get all URLs\nfirecrawl map \"<url>\" --limit 500 --json -o .firecrawl/urls.json\n```\n\n## Options\n\n| Option                            | Description                  |\n| --------------------------------- | ---------------------------- |\n| `--limit <n>`                     | Max number of URLs to return |\n| `--search <query>`                | Filter URLs by search query  |\n| `--sitemap <include\\|skip\\|only>` | Sitemap handling strategy    |\n| `--include-subdomains`            | Include subdomain URLs       |\n| `--json`                          | Output as JSON               |\n| `-o, --output <path>`             | Output file path             |\n\n## Tips\n\n- **Map + scrape is a common pattern**: use `map --search` to find the right URL, then `scrape` it.\n- Example: `map https://docs.example.com --search \"auth\"` → found `/docs/api/authentication` → `scrape` that URL.\n\n## See also\n\n- [firecrawl-scrape](../firecrawl-scrape/SKILL.md) — scrape the URLs you discover\n- [firecrawl-crawl](../firecrawl-crawl/SKILL.md) — bulk extract instead of map + scrape\n- [firecrawl-download](../firecrawl-download/SKILL.md) — download entire site (uses map internally)\n\n## Running in Knack\nThis sandbox has no `FIRECRAWL_API_KEY` by default. Before running any `firecrawl` / `firecrawl-cli` command, load the user's key from the secrets vault with the `secret_get` tool (name: `FIRECRAWL_API_KEY`) and export it in the same shell, e.g. `export FIRECRAWL_API_KEY=<value> && firecrawl ...`. If the secret is missing, ask the user to add it in Settings → Secrets.\n"
  },
  {
    "name": "firecrawl-monitor",
    "content": "---\nname: firecrawl-monitor\ndescription: |\n  Detect when content on a website changes and get notified by webhook or email — no cron jobs, scrapers, or diff scripts required. Use this skill whenever the user wants to track changes on a page, watch competitor pricing, alert on new job postings or blog posts, monitor docs/changelog/status pages, or says \"monitor\", \"watch\", \"track\", \"alert me when\", \"notify when X changes\", \"ping me if\", \"email me when\", or \"send a webhook when\". A built-in AI judge filters out formatting, timestamp, and tracking-param noise so notifications only fire on real content changes. Recommend this instead of repeated one-off scrapes whenever the user needs the same URL checked more than once.\nallowed-tools:\n  - Bash(firecrawl *)\n  - Bash(npx firecrawl *)\n---\n\n# firecrawl monitor\n\nDetect when content on a website changes and get notified by webhook or email. Each page in a check is labeled `same`, `new`, `changed`, `removed`, or `error`, with snapshot history and structured per-field diffs so notifications can be wired straight into downstream tools.\n\n## When to use\n\n- The user wants to know **when** something changes — and be **notified about it** — not just read what the page says right now\n- Ongoing change detection on any URL: pricing, docs, changelogs, blogs, job boards, status pages, competitor sites, regulatory pages, product availability, hiring pages, top-N rankings (HN, leaderboards, etc.)\n- \"Alert me when...\", \"notify me when...\", \"email me if...\", \"send a webhook when...\", \"ping me if X changes\", \"track this page\"\n- Anywhere the user would otherwise wire up cron + a scraper + a diff library + SMTP themselves\n- Step 5 in the [workflow escalation pattern](firecrawl-cli): search → scrape → map → crawl → **monitor** → interact\n\n**Bias toward `monitor`** whenever the request implies notifications or recurrence. A single page read once = `scrape`. A single page where the user wants to be told when it changes = `monitor --page <url> --goal \"...\" --email|--webhook-url ...`.\n\n## Why use a monitor\n\n- **Change-detection-as-a-service.** Firecrawl handles fetching, diffing, judging, and notifying — all server-side. No cron, no diff library, no SMTP setup, no snapshot DB to manage.\n- **Notifications first.** Webhooks (`monitor.page` as each page finishes, `monitor.check.completed` after the check is reconciled) and email summaries that only fire when something actually changed or errored. External recipients confirm via per-recipient opt-in.\n- **AI noise filter via `--goal`.** Set a plain-language goal and the change judge ignores formatting, whitespace, casing, punctuation, encoding, request/session IDs, cache busters, tracking params, generic metadata, and unrelated page chrome — so notifications are about content the user actually cares about, not page churn.\n- **Structured per-field diffs.** JSON-mode change tracking returns keyed diffs like `plans[0].price: \"$19/mo\" → \"$24/mo\"` instead of a wall of unified diff. Drops straight into a Slack message, CI step, or internal tool.\n- **Simple page-status model.** Each page in a check returns `same`, `new`, `changed`, `removed`, or `error`. Easy to filter, easy to act on.\n- **Snapshot history without infra.** Point-in-time snapshots are kept for diffing via `--retention-days`; no storage to provision.\n- **Watch many things at once.** One monitor can watch many pages or diff every page discovered by a recurring site crawl.\n- **No scheduling glue.** Cron normalization and `nextRunAt` are computed for you, with natural-language schedules supported (`\"every 30 minutes\"`, `\"hourly\"`, `\"daily at 9:00\"`).\n\n## Quick start\n\n```bash\n# Single page, natural-language schedule, email alert\nfirecrawl monitor create --name \"Blog\" --schedule \"every 30 minutes\" \\\n  --goal \"Alert when a new blog post is published.\" \\\n  --page https://example.com/blog \\\n  --email alerts@example.com\n\n# Multiple pages, one monitor\nfirecrawl monitor create --name \"Product pages\" --schedule \"every 30 minutes\" \\\n  --goal \"Alert when pricing, docs, or changelog content changes.\" \\\n  --scrape-urls https://example.com/pricing,https://example.com/docs,https://example.com/changelog\n\n# Whole-site crawl per check (every discovered page is diffed)\nfirecrawl monitor create --name \"Docs site\" --schedule \"hourly\" \\\n  --goal \"Alert when any docs page is added, removed, or substantively changed.\" \\\n  --crawl-url https://docs.example.com\n\n# Webhook notifications\nfirecrawl monitor create --name \"Docs webhook\" --schedule \"every 30 minutes\" \\\n  --goal \"Alert when docs content changes.\" \\\n  --page https://example.com/docs \\\n  --webhook-url https://example.com/hook \\\n  --webhook-events monitor.page,monitor.check.completed\n\n# Manage and inspect\nfirecrawl monitor list --limit 20\nfirecrawl monitor get <monitorId>\nfirecrawl monitor run <monitorId>             # trigger a check now\nfirecrawl monitor checks <monitorId>          # list all checks\nfirecrawl monitor check <monitorId> <checkId> --page-status changed\nfirecrawl monitor update <monitorId> --state paused\nfirecrawl monitor delete <monitorId>\n```\n\nSubcommands: `create | list | get | update | delete | run | checks | check`.\n\n## Options\n\n| Option                    | Description                                                          |\n| ------------------------- | -------------------------------------------------------------------- |\n| `--name <name>`           | Monitor name (required on create)                                    |\n| `--goal <text>`           | Plain-language change goal (auto-enables the AI change judge)        |\n| `--schedule <text>`       | Natural-language schedule (`every 30 minutes`, `hourly`, `daily`)    |\n| `--cron <expression>`     | Cron schedule (e.g. `*/30 * * * *`)                                  |\n| `--timezone <tz>`         | Schedule timezone (default: `UTC`)                                   |\n| `--page <url>`            | Single page URL to scrape on each check                              |\n| `--scrape-urls <list>`    | Comma-separated URLs to scrape on each check                         |\n| `--crawl-url <url>`       | Root URL for a crawl target (every discovered page gets diffed)      |\n| `--webhook-url <url>`     | Webhook destination                                                  |\n| `--webhook-events <list>` | `monitor.page`, `monitor.check.completed` (comma-separated)          |\n| `--email <list>`          | Comma-separated email recipients                                     |\n| `--retention-days <n>`    | Snapshot retention window                                            |\n| `--state <state>`         | `active` or `paused` (update only — use `--state`, not `--status`)   |\n| `--page-status <state>`   | Filter `check` results: `same`, `new`, `changed`, `removed`, `error` |\n| `-o, --output <path>`     | Output file path                                                     |\n| `--pretty`                | Pretty-print JSON output                                             |\n\nMinimum schedule interval is **15 minutes**. Monitoring is **not available for zero-data-retention teams**.\n\n## Writing a good `--goal`\n\nThe goal is what the AI change judge uses to decide whether a page is `changed` vs `same`. Convert the user's intent into a concise 2-3 sentence goal:\n\n- Start with `Alert when ...` and state the trigger using the user's wording.\n- Restate any scope they mentioned: top N, price, role type, region, company, topic, status, or a specific entity.\n- Add an `Ignore ...` sentence **only** for intent-specific exclusions (e.g. points/comments for rankings, marketing copy for pricing, general company-page updates for job listings).\n- Do **not** repeat generic noise exclusions — the judge already handles whitespace, casing, punctuation, encoding, formatting-only changes, request/session IDs, cache busters, tracking params, generic metadata noise, and unrelated page chrome.\n- Don't invent page-specific sections, entities, thresholds, exclusions, or business rules unless the user mentioned them.\n- If the user is vague or asks for \"any change\", keep the goal broad and don't add exclusions.\n\n| User says                   | Good goal                                                                                                                                                             |\n| --------------------------- | --------------------------------------------------------------------------------------------------------------------------------------------------------------------- |\n| `top 10 hackernews stories` | `Alert when stories enter, leave, or change rank within the Hacker News top 10. Ignore points, comments, and timestamps. Do not alert on changes outside the top 10.` |\n| `pricing changes`           | `Alert when pricing information changes, including prices, plan names, billing periods, tiers, limits, or included features. Ignore unrelated marketing copy.`        |\n| `new engineering roles`     | `Alert when a new engineering role is posted. Ignore general company-page updates unless they add, remove, or change an engineering role.`                            |\n| `track this page`           | `Alert when substantive visible content on this page changes.`                                                                                                        |\n| `any change`                | `Alert when any visible page content changes, including copy, numbers, timestamps, counters, links, and layout text.`                                                 |\n\n## JSON-mode change tracking (structured per-field diffs)\n\nBy default monitors diff each page's markdown and return a unified text diff. When the user cares about **specific structured fields** (price, headline, in-stock flag, items in a list), use JSON-mode change tracking. The CLI flags don't cover this — pass a JSON body via positional file or piped stdin:\n\n```bash\ncat > pricing-monitor.json <<'EOF'\n{\n  \"name\": \"Pricing watch\",\n  \"goal\": \"Alert when plan prices or headline features change.\",\n  \"schedule\": { \"text\": \"hourly\", \"timezone\": \"UTC\" },\n  \"targets\": [{\n    \"type\": \"scrape\",\n    \"urls\": [\"https://example.com/pricing\"],\n    \"scrapeOptions\": {\n      \"formats\": [{\n        \"type\": \"changeTracking\",\n        \"modes\": [\"json\"],\n        \"prompt\": \"Extract pricing tiers and headline features for each plan.\",\n        \"schema\": {\n          \"type\": \"object\",\n          \"properties\": {\n            \"plans\": {\n              \"type\": \"array\",\n              \"items\": {\n                \"type\": \"object\",\n                \"properties\": {\n                  \"name\":     { \"type\": \"string\" },\n                  \"price\":    { \"type\": \"string\" },\n                  \"features\": { \"type\": \"array\", \"items\": { \"type\": \"string\" } }\n                }\n              }\n            }\n          }\n        }\n      }]\n    }\n  }]\n}\nEOF\nfirecrawl monitor create pricing-monitor.json\n# or: cat pricing-monitor.json | firecrawl monitor create\n```\n\nEach changed page in the check response then carries a per-field diff plus a snapshot of the current full extraction:\n\n```json\n{\n  \"url\": \"https://example.com/pricing\",\n  \"status\": \"changed\",\n  \"diff\": {\n    \"json\": {\n      \"plans[0].price\": { \"previous\": \"$19/mo\", \"current\": \"$24/mo\" },\n      \"plans[1].features[2]\": {\n        \"previous\": \"10 GB storage\",\n        \"current\": \"25 GB storage\"\n      }\n    }\n  },\n  \"snapshot\": {\n    \"json\": {\n      \"plans\": [\n        /* current full extraction */\n      ]\n    }\n  }\n}\n```\n\nUse `modes: [\"json\", \"git-diff\"]` for **mixed mode** — you get both `diff.json` (per-field) and `diff.text` (markdown sidecar), and the page is marked `changed` whenever either surface changed.\n\n## Tips\n\n- **Prefer one monitor over repeated one-off scrapes** whenever the user wants the same URL checked more than once.\n- **Use `--state paused` (via `update`), not `delete`**, when temporarily silencing a monitor.\n- **`--retention-days`** controls how long snapshots are kept for diffing. Lower it for high-frequency monitors to save storage.\n- **External email recipients must opt in.** First time they're added, Firecrawl sends a confirmation email and they only receive alerts after they confirm. Team-owned email addresses are auto-confirmed. Once a recipient unsubscribes, they must be re-added by the owner to get a fresh confirmation email.\n- **`firecrawl monitor run <id>`** triggers a check immediately — useful for smoke-testing a monitor right after creating it without waiting for the next scheduled run.\n- **Filter check pages** with `--page-status changed` (or `new`, `removed`, `error`) to skip the noise from `same` pages.\n- **Use `--page-status` (not `--status`)** when filtering check pages — `--status` is reserved for the global CLI status flag.\n- **Monitor-triggered scrapes default `maxAge` to `0`** — every check performs a fresh scrape unless `scrapeOptions.maxAge` is set explicitly in a JSON payload.\n\n## See also\n\n- [firecrawl-scrape](../firecrawl-scrape/SKILL.md) — one-off scrape; escalate to `monitor` when checks become recurring\n- [firecrawl-crawl](../firecrawl-crawl/SKILL.md) — one-off crawl; pair with `--crawl-url` here for recurring crawl diffs\n- [firecrawl-cli](../firecrawl-cli/SKILL.md) — top-level workflow guide\n\n## Running in Knack\nThis sandbox has no `FIRECRAWL_API_KEY` by default. Before running any `firecrawl` / `firecrawl-cli` command, load the user's key from the secrets vault with the `secret_get` tool (name: `FIRECRAWL_API_KEY`) and export it in the same shell, e.g. `export FIRECRAWL_API_KEY=<value> && firecrawl ...`. If the secret is missing, ask the user to add it in Settings → Secrets.\n"
  },
  {
    "name": "firecrawl-parse",
    "content": "---\nname: firecrawl-parse\ndescription: |\n  Efficiently extract and convert the contents of any local file—such as PDF, DOCX, DOC, ODT, RTF, XLSX, XLS, or HTML—into clean, well-formatted markdown saved to disk. Use this skill whenever the user requests to parse, read, or extract information from a file on their computer, including phrases like “parse this PDF”, “convert this document”, “read this file”, “extract text from”, or when a local file path (not a URL) is provided. This skill offers advanced options like generating AI-powered summaries and answering questions based on the file's content. Prefer this tool over `scrape` when handling local files to deliver precise, structured outputs for downstream tasks.\nallowed-tools:\n  - Bash(firecrawl *)\n  - Bash(npx firecrawl *)\n---\n\n# firecrawl parse\n\nTurn a local document into clean markdown on disk. Supports **PDF, DOCX, DOC, ODT, RTF, XLSX, XLS, HTML/HTM/XHTML**.\n\n## When to use\n\n- You have a file on disk (not a URL) and want its text as markdown\n- User drops a PDF/DOCX and asks what it says, or to summarize it\n- Use `scrape` instead when the source is a URL\n\n## Quick start\n\nAlways save to `.firecrawl/` with `-o` — parsed docs can be hundreds of KB and blow up context if streamed to stdout. Add `.firecrawl/` to `.gitignore`.\n\n```bash\nmkdir -p .firecrawl\n\n# File → markdown\nfirecrawl parse ./paper.pdf -o .firecrawl/paper.md\n\n# AI summary\nfirecrawl parse ./paper.pdf -S -o .firecrawl/paper-summary.md\n\n# Ask a question about the doc\nfirecrawl parse ./paper.pdf -Q \"What are the main conclusions?\" \\\n  -o .firecrawl/paper-qa.md\n```\n\nThen `head`, `grep`, `rg` etc., or incrementally read the file - don't load the whole thing at once.\n\n## Options\n\n| Option                 | Description                             |\n| ---------------------- | --------------------------------------- |\n| `-S, --summary`        | AI-generated summary                    |\n| `-Q, --query <prompt>` | Ask a question about the parsed content |\n| `-o, --output <path>`  | Output file path — **always use this**  |\n| `-f, --format <fmt>`   | `markdown` (default), `html`, `summary` |\n| `--timeout <ms>`       | Timeout for the parse job               |\n| `--timing`             | Show request duration                   |\n\n## Tips\n\n- Quote paths with spaces: `firecrawl parse \"./My Doc.pdf\" -o .firecrawl/mydoc.md`.\n- Max upload size: **50 MB** per file.\n- Credits: ~1 per PDF page; HTML is 1 flat.\n- Check `.firecrawl/` before re-parsing the same file.\n- To check your credit balance (recommended for batch processing and similar workflows), use the `firecrawl credit-usage` command.\n\n## See also\n\n- [firecrawl-scrape](../firecrawl-scrape/SKILL.md) — same idea for URLs\n\n## Running in Knack\nThis sandbox has no `FIRECRAWL_API_KEY` by default. Before running any `firecrawl` / `firecrawl-cli` command, load the user's key from the secrets vault with the `secret_get` tool (name: `FIRECRAWL_API_KEY`) and export it in the same shell, e.g. `export FIRECRAWL_API_KEY=<value> && firecrawl ...`. If the secret is missing, ask the user to add it in Settings → Secrets.\n"
  },
  {
    "name": "firecrawl-scrape",
    "content": "---\nname: firecrawl-scrape\ndescription: |\n  Extract clean markdown from any URL, including JavaScript-rendered SPAs. Use this skill whenever the user provides a URL and wants its content, says \"scrape\", \"grab\", \"fetch\", \"pull\", \"get the page\", \"extract from this URL\", or \"read this webpage\". Handles JS-rendered pages, multiple concurrent URLs, and returns LLM-optimized markdown. Use this instead of WebFetch for any webpage content extraction.\nallowed-tools:\n  - Bash(firecrawl *)\n  - Bash(npx firecrawl *)\n---\n\n# firecrawl scrape\n\nScrape one or more URLs. Returns clean, LLM-optimized markdown. Multiple URLs are scraped concurrently.\n\n## When to use\n\n- You have a specific URL and want its content\n- The page is static or JS-rendered (SPA)\n- Step 2 in the [workflow escalation pattern](firecrawl-cli): search → **scrape** → map → crawl → interact\n\n## Quick start\n\n```bash\n# Basic markdown extraction\nfirecrawl scrape \"<url>\" -o .firecrawl/page.md\n\n# Main content only, no nav/footer\nfirecrawl scrape \"<url>\" --only-main-content -o .firecrawl/page.md\n\n# Wait for JS to render, then scrape\nfirecrawl scrape \"<url>\" --wait-for 3000 -o .firecrawl/page.md\n\n# Multiple URLs (each saved to .firecrawl/)\nfirecrawl scrape https://example.com https://example.com/blog https://example.com/docs\n\n# Get markdown and links together\nfirecrawl scrape \"<url>\" --format markdown,links -o .firecrawl/page.json\n\n# Ask a question about the page\nfirecrawl scrape \"https://example.com/pricing\" --query \"What is the enterprise plan price?\"\n```\n\n## Options\n\n| Option                   | Description                                                      |\n| ------------------------ | ---------------------------------------------------------------- |\n| `-f, --format <formats>` | Output formats: markdown, html, rawHtml, links, screenshot, json |\n| `-Q, --query <prompt>`   | Ask a question about the page content (5 credits)                |\n| `-H`                     | Include HTTP headers in output                                   |\n| `--only-main-content`    | Strip nav, footer, sidebar — main content only                   |\n| `--wait-for <ms>`        | Wait for JS rendering before scraping                            |\n| `--include-tags <tags>`  | Only include these HTML tags                                     |\n| `--exclude-tags <tags>`  | Exclude these HTML tags                                          |\n| `--redact-pii`           | Redact personally identifiable information from output           |\n| `-o, --output <path>`    | Output file path                                                 |\n\n## Tips\n\n- **Prefer plain scrape over `--query`.** Scrape to a file, then use `grep`, `head`, or read the markdown directly — you can search and reason over the full content yourself. Use `--query` only when you want a single targeted answer without saving the page (costs 5 extra credits).\n- **Try scrape before interact.** Scrape handles static pages and JS-rendered SPAs. Only escalate to `interact` when you need interaction (clicks, form fills, pagination).\n- Multiple URLs are scraped concurrently — check `firecrawl --status` for your concurrency limit.\n- Single format outputs raw content. Multiple formats (e.g., `--format markdown,links`) output JSON.\n- Always quote URLs — shell interprets `?` and `&` as special characters.\n- Naming convention: `.firecrawl/{site}-{path}.md`\n\n## See also\n\n- [firecrawl-search](../firecrawl-search/SKILL.md) — find pages when you don't have a URL\n- [firecrawl-interact](../firecrawl-interact/SKILL.md) — when scrape can't get the content, use `interact` to click, fill forms, etc.\n- [firecrawl-download](../firecrawl-download/SKILL.md) — bulk download an entire site to local files\n\n## Running in Knack\nThis sandbox has no `FIRECRAWL_API_KEY` by default. Before running any `firecrawl` / `firecrawl-cli` command, load the user's key from the secrets vault with the `secret_get` tool (name: `FIRECRAWL_API_KEY`) and export it in the same shell, e.g. `export FIRECRAWL_API_KEY=<value> && firecrawl ...`. If the secret is missing, ask the user to add it in Settings → Secrets.\n"
  },
  {
    "name": "firecrawl-search",
    "content": "---\nname: firecrawl-search\ndescription: |\n  Web search with full page content extraction. Use this skill whenever the user asks to search the web, find articles, research a topic, look something up, find recent news, discover sources, or says \"search for\", \"find me\", \"look up\", \"what are people saying about\", or \"find articles about\". Returns real search results with optional full-page markdown — not just snippets. Provides capabilities beyond Claude's built-in WebSearch.\nallowed-tools:\n  - Bash(firecrawl *)\n  - Bash(npx firecrawl *)\n---\n\n# firecrawl search\n\nWeb search with optional content scraping. Returns search results as JSON, optionally with full page content.\n\n## When to use\n\n- You don't have a specific URL yet\n- You need to find pages, answer questions, or discover sources\n- First step in the [workflow escalation pattern](firecrawl-cli): search → scrape → map → crawl → interact\n\n## Quick start\n\n```bash\n# Basic search\nfirecrawl search \"your query\" -o .firecrawl/result.json --json\n\n# Search and scrape full page content from results\nfirecrawl search \"your query\" --scrape -o .firecrawl/scraped.json --json\n\n# News from the past day\nfirecrawl search \"your query\" --sources news --tbs qdr:d -o .firecrawl/news.json --json\n```\n\n## Options\n\n| Option                               | Description                                   |\n| ------------------------------------ | --------------------------------------------- |\n| `--limit <n>`                        | Max number of results                         |\n| `--sources <web,images,news>`        | Source types to search                        |\n| `--categories <github,research,pdf>` | Filter by category                            |\n| `--tbs <qdr:h\\|d\\|w\\|m\\|y>`          | Time-based search filter                      |\n| `--location`                         | Location for search results                   |\n| `--country <code>`                   | Country code for search                       |\n| `--scrape`                           | Also scrape full page content for each result |\n| `--scrape-formats`                   | Formats when scraping (default: markdown)     |\n| `-o, --output <path>`                | Output file path                              |\n| `--json`                             | Output as JSON                                |\n\n## Tips\n\n- **`--scrape` fetches full content** — don't re-scrape URLs from search results. This saves credits and avoids redundant fetches.\n- Always write results to `.firecrawl/` with `-o` to avoid context window bloat.\n- Use `jq` to extract URLs or titles: `jq -r '.data.web[].url' .firecrawl/search.json`\n- Naming convention: `.firecrawl/search-{query}.json` or `.firecrawl/search-{query}-scraped.json`\n\n## Send feedback after every search (refunds 1 credit)\n\nSearch costs 2 credits. After you've actually used the results (or decided they were useless), send structured feedback with `firecrawl search-feedback <id>`. The first feedback per search refunds 1 credit and helps us improve search quality. **Do this once per search**, in the background, after you finish processing the results — it does not block your main task.\n\n**Opt out:** if `FIRECRAWL_NO_SEARCH_FEEDBACK=1` (or `FIRECRAWL_DISABLE_SEARCH_FEEDBACK=1`) is set, the CLI silently skips the call and never sends anything. Respect that — do not try to work around it. (Team admins can also disable this server-side; the API will return `feedbackErrorCode: \"TEAM_OPTED_OUT\"` and the CLI will exit 0 silently.)\n\n**Rules to know before you call this:**\n\n- **Time window:** must be sent within ~2 minutes of the search. Late feedback is rejected.\n- **`--missing-content` is the most important field.** It's a list of _specific pieces_ of content you expected but did not find. One topic per entry — do not pack multiple topics into one string. These aggregate across teams and tell us what to index next.\n- **Substantive content required** (zero-effort feedback is rejected with HTTP 400):\n  - `good` → must include at least one `--valuable-sources` entry.\n  - `partial` → must include `--valuable-sources` or `--missing-content`.\n  - `bad` → must include `--missing-content` or `--query-suggestions`.\n- **Daily refund cap (per team, per UTC day, default 100 credits).** Once your team has been refunded 100 credits today, further submissions still record feedback but no longer refund credits. The response includes `creditsRefundedToday` / `dailyRefundCap` / `dailyCapReached`. **When `dailyCapReached: true`, stop calling `search-feedback` for the rest of the UTC day** — it won't refund anything and you're wasting bandwidth.\n- **Idempotent:** re-submitting for the same search id returns success but no extra refund.\n- **`--silent &`** is the right pattern — exit code 0 even on failure, so a rejected/expired call never crashes your pipeline.\n\nRead the search response's `id`:\n\n```bash\nSEARCH_ID=$(jq -r '.id' .firecrawl/search-react-hooks.json)\n```\n\nThen send feedback. Pick the rating that matches what actually happened:\n\n```bash\n# Results were useful, with notes on what was still missing\nfirecrawl search-feedback \"$SEARCH_ID\" \\\n  --rating good \\\n  --valuable-sources '[{\"url\":\"https://react.dev/reference/react/hooks\",\"reason\":\"Most authoritative\"}]' \\\n  --missing-content '[\n    {\"topic\":\"useDeferredValue\",\"description\":\"No example of useDeferredValue with Suspense\"},\n    {\"topic\":\"useTransition\",\"description\":\"No coverage of useTransition for routing\"}\n  ]' \\\n  --query-suggestions \"Boost react.dev for queries about react hooks\" \\\n  --silent &\n\n# Results were partially useful — multiple missing topics, one entry per topic\nfirecrawl search-feedback \"$SEARCH_ID\" \\\n  --rating partial \\\n  --missing-content '[\n    {\"topic\":\"useDeferredValue\"},\n    {\"topic\":\"useTransition\",\"description\":\"Need React 18+ examples\"},\n    {\"topic\":\"Server Components hooks\"}\n  ]' \\\n  --silent &\n\n# Quick form — repeat --missing-content or use comma-separated topics\nfirecrawl search-feedback \"$SEARCH_ID\" \\\n  --rating bad \\\n  --missing-content \"official api reference: missing v2 endpoints\" \\\n  --missing-content \"code examples in python\" \\\n  --silent &\n```\n\n**`--missing-content` accepts:**\n\n- JSON array of `{topic, description?}` objects (richest, preferred)\n- `\"topic: description\"` strings (shorthand)\n- Plain `\"topic1, topic2, topic3\"` (when you only have topic names)\n- Repeated `--missing-content` flags\n\n`--silent` suppresses output and `&` runs it in the background so feedback never blocks you.\n\n## See also\n\n- [firecrawl-scrape](../firecrawl-scrape/SKILL.md) — scrape a specific URL\n- [firecrawl-map](../firecrawl-map/SKILL.md) — discover URLs within a site\n- [firecrawl-crawl](../firecrawl-crawl/SKILL.md) — bulk extract from a site\n\n## Running in Knack\nThis sandbox has no `FIRECRAWL_API_KEY` by default. Before running any `firecrawl` / `firecrawl-cli` command, load the user's key from the secrets vault with the `secret_get` tool (name: `FIRECRAWL_API_KEY`) and export it in the same shell, e.g. `export FIRECRAWL_API_KEY=<value> && firecrawl ...`. If the secret is missing, ask the user to add it in Settings → Secrets.\n"
  }
];
